class Animal:
    def __init__(self, name, sound):
        self.name = name
        self.sound = sound

    def speak(self):
        return f'{self.name} каже {self.sound}!'

    def __str__(self):
        return f'{self.__class__.__name__}: {self.name}'

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name, 'Гав')
        self.breed = breed

    def fetch(self, item):
        return f'{self.name} приніс {item}'

rex = Dog('Рекс', 'Лабрадор')
print(rex.speak())
print(rex.fetch('м'яч'))
print(rex)
